import{_ as i,o,c as t,a4 as a}from"./chunks/framework.EYT3XhWU.js";const h=JSON.parse('{"title":"前言","description":"","frontmatter":{},"headers":[],"relativePath":"行测/资料分析/index.md","filePath":"行测/资料分析/index.md"}'),e={name:"行测/资料分析/index.md"};function r(n,l,s,p,c,d){return o(),t("div",null,[...l[0]||(l[0]=[a('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h1><p>字数: 775 字 时长: 3 分钟</p><ol><li><strong>题量</strong>：3/4篇×5道=15/20道题，单个题目分值较大，在1分左右。</li><li><strong>基础目标</strong>：每篇材料控制在7分钟以内，总正确率在80%以上</li><li><strong>进阶目标</strong>：每篇材料控制在5分钟以内，总正确率在80%以上</li><li></li></ol><h2 id="一、题型与特点" tabindex="-1">一、题型与特点 <a class="header-anchor" href="#一、题型与特点" aria-label="Permalink to “一、题型与特点”">​</a></h2><ul><li><strong>题型</strong>：资料分析材料通常由统计性的图表、数字及文字构成；一段材料有5个小问题，需根据资料分析所提供的信息进行比较、分析和计算。</li><li><strong>特点</strong>：重点考查列式能力、计算比较能力和分析能力，需要考生熟记基本公式，强化练习速算，学会对材料的整合、化繁为简。并且多是围绕7个核心考点来命题，分别是基期值，现期值，增长量，增长率，倍数，比重，平均数。</li></ul><ol><li><blockquote><p>资料分析是行测最重要的模块，高手20分钟以内完成，如果你花30~35分钟完成，多的10~15分钟别人去做数量了，且其他版块游刃有余，最后直接总分超你7~10余分！</p></blockquote></li><li><blockquote><p>哪怕别人20min完成，你25min完成，别人的5min用来做对一两个数量，然后结合选A猜B方法，再猜对几个数量，也是可以拉你5分的!</p></blockquote></li><li><blockquote><p>并且，资料相对其他板块来说是最好提升的，且提升最容易见效的。我们不求极致，尽量得到90%分数即可，资料分析是唯一有希望得满分的模块，但是不要强求，因为还有时间限制，为大局，允许放弃个别题目</p></blockquote></li></ol><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to “二、解题步骤”">​</a></h2><ul><li><strong>预先浏览</strong>：看今年的题目有多少道题，心中有数</li><li><strong>先易后难、遇难则跳</strong>：一般材料由易到难顺序 图（找数好找）→表（数据清晰）→综合→文字。</li><li><strong>找数据——列公式——算结果</strong></li></ul><h2 id="三、大神做题共同点" tabindex="-1">三、大神做题共同点 <a class="header-anchor" href="#三、大神做题共同点" aria-label="Permalink to “三、大神做题共同点”">​</a></h2><ol><li><p><strong>极少动笔</strong>，几乎80%上的做题过程在分析或口算；且熟练掌握各类口算、笔算技巧。</p></li><li><p><strong>会很多秒杀技巧或快速解题法</strong>，一套资料下来至少涉及2-4这类技巧方法，一个技巧可以节省1分钟左右。</p></li><li><p><strong>对各类题型，考点极其熟悉</strong>，看到题目能立刻想到考点和思路，立刻分析。</p></li><li><p>启示</p><p>：</p><ol><li>①资料里：分析&gt;口算&gt;笔算；分析第一，能口算的尽量口算，最多过程写几个数字，一旦手写，必定耽误时间。同时记忆好各类百化分、积累练熟各类计算技巧。</li><li>②熟练公式概念，多积累相关解题技巧，这样在考场上才能发挥出来。</li><li>③考点反应迟缓或根本想不起来，便是基础不牢；提速的前提在于基础扎实，基础不牢，速度肯定提不上去；我们平时可多总结练习题型和考点，至少练到看到题目能立即想到考点和方法的程度。</li></ol></li></ol>',10)])])}const _=i(e,[["render",r]]);export{h as __pageData,_ as default};
